// ============================================================================
// CALIBRATION — Scale factors computed at module init
// ============================================================================

// Calibration factors bridge the gap between simplified JS math and Excel's
// full-precision formulas. Computed once at module load by comparing engine
// output at BASE_CASE against known Excel values.

const EXCEL_TARGETS = {
  // 'returns.grossMOIC': 0,    // Excel base case value
  // 'returns.netMOIC': 0,
  // 'returns.grossIRR': 0,
  // 'returns.netIRR': 0,
  // {{ADDITIONAL_TARGETS}}
};

let _calibration = {};

function _initCalibration() {
  const raw = _computeRaw(BASE_CASE);
  const factors = {};

  for (const [key, excelValue] of Object.entries(EXCEL_TARGETS)) {
    const engineValue = _getNestedValue(raw, key);
    if (engineValue != null && Math.abs(engineValue) > 1e-12) {
      factors[key] = excelValue / engineValue;
    } else {
      factors[key] = 1;
    }
  }

  _calibration = factors;
}

