// ============================================================================
// PUBLIC API — Calibrated computation
// ============================================================================

/**
 * Compute the full financial model with calibration.
 *
 * @param {Object} inputs - Model inputs (see BASE_CASE for structure)
 * @returns {Object} Complete model output
 */
export function computeModel(inputs) {
  const raw = _computeRaw(inputs);

  // Apply calibration factors
  for (const [key, factor] of Object.entries(_calibration)) {
    const current = _getNestedValue(raw, key);
    if (current != null) {
      _setNestedValue(raw, key, current * factor);
    }
  }

  return raw;
}

// ============================================================================
// UTILITIES
// ============================================================================

function _getNestedValue(obj, path) {
  return path.split('.').reduce((curr, key) => curr?.[key], obj);
}

function _setNestedValue(obj, path, value) {
  const keys = path.split('.');
  let curr = obj;
  for (let i = 0; i < keys.length - 1; i++) {
    if (curr[keys[i]] == null) curr[keys[i]] = {};
    curr = curr[keys[i]];
  }
  curr[keys[keys.length - 1]] = value;
}

// ============================================================================
// INIT — Run calibration on module load
// ============================================================================

_initCalibration();
